use bids_rust::{BidsProject, Result};
use tempfile::TempDir;
use std::fs;

#[test]
fn test_basic_bids_functionality() -> Result<()> {
    println!("Testing basic BIDS functionality...");

    // Create a minimal test BIDS dataset
    let temp_dir = TempDir::new()?;
    let root = temp_dir.path();

    // Create required BIDS files
    let participants_content = "participant_id\tsex\tage\nsub-01\tF\t25\nsub-02\tM\t30\n";
    fs::write(root.join("participants.tsv"), participants_content)?;

    let dataset_description = serde_json::json!({
        "Name": "Test Dataset",
        "BIDSVersion": "1.8.0",
        "Description": "A test BIDS dataset for verifying functionality"
    });
    fs::write(
        root.join("dataset_description.json"),
        serde_json::to_string_pretty(&dataset_description)?,
    )?;

