//! Integration tests using real BIDS example datasets
//!
//! These tests run against actual BIDS datasets from bids-examples.
//! They will be skipped if the datasets are not available locally.

use bids_rust::{BidsProject, Result};
use std::path::PathBuf;

mod common;
use common::bids_examples::*;

/// Test basic functionality with ds000001
#[test]
fn test_ds000001_basic() -> Result<()> {
    let dataset_path = require_example_dataset!("ds000001");

    // Open the project
    let project = BidsProject::new(&dataset_path)?;

    // Basic assertions about ds000001
    assert_eq!(project.name, "ds000001");

    // Get participants
    let participants = project.participants();
    assert!(!participants.is_empty(), "ds000001 should have participants");

    // Check for functional data
    let func_files = project.search()
        .datatype("func")
        .suffix("bold")
        .extension("nii.gz")
        .execute()?;
    assert!(!func_files.is_empty(), "ds000001 should have functional data");

    // Check for task information
    let tasks: Vec<String> = func_files.iter()
        .filter_map(|f| f.entities.get("task"))
        .collect::<std::collections::HashSet<_>>()
        .into_iter()
        .cloned()
        .collect();
    assert!(!tasks.is_empty(), "ds000001 should have task information");

    Ok(())
}

/// Test multi-task dataset ds000002
#[test]
fn test_ds000002_multiple_tasks() -> Result<()> {
    let dataset_path = require_example_dataset!("ds000002");

    let project = BidsProject::new(&dataset_path)?;

    // ds000002 has multiple tasks
    let tasks = project.search()
        .datatype("func")
        .find_files()?
        .iter()
        .filter_map(|f| f.entities.get("task"))
        .collect::<std::collections::HashSet<_>>();

    assert!(tasks.len() > 1, "ds000002 should have multiple tasks");

    Ok(())
}

/// Test synthetic dataset structure
#[test]
fn test_synthetic_dataset() -> Result<()> {
    let dataset_path = require_example_dataset!("synthetic");

    let project = BidsProject::new(&dataset_path)?;

    // Synthetic dataset should have well-structured data
    // Check for various modalities
    let modalities = vec!["anat", "func", "dwi", "fmap"];

    for modality in modalities {
        let files = project.search()
            .datatype(modality)
            .execute()?;
        println!("Found {} {} files in synthetic dataset", files.len(), modality);
    }

    Ok(())
}

/// Test dataset validation with real data
#[test]
fn test_real_dataset_validation() -> Result<()> {
    let manager = BidsExamplesManager::new(BidsExamplesManager::default_cache_dir());
    let available = manager.list_available();

    if available.is_empty() {
        eprintln!("No BIDS example datasets available for validation testing");
        return Ok(());
    }

    for example in available.iter().take(3) {  // Test first 3 available datasets
        println!("\nValidating dataset: {}", example.name);

        let project = BidsProject::new(&example.path)?;

        // Run validation
        match project.validate() {
            Ok(report) => {
                println!("  ✓ Dataset {} is valid", example.name);
                if !report.warnings.is_empty() {
                    println!("  ⚠ {} warnings found", report.warnings.len());
                }
            }
            Err(e) => {
                println!("  ✗ Validation failed: {}", e);
            }
        }
    }

    Ok(())
}

/// Test working with event files in real datasets
#[test]
fn test_real_event_files() -> Result<()> {
    let dataset_path = require_example_dataset!("ds000003");

    let project = BidsProject::new(&dataset_path)?;

    // Find event files
    let event_files = project.search()
        .suffix("events")
        .extension("tsv")
        .execute()?;

    if !event_files.is_empty() {
        // Read first event file
        let event_file = &event_files[0];
        let events = event_file.read_events()?;

        // Check basic event structure
        assert!(!events.is_empty(), "Events should not be empty");
        for event in &events {
            assert!(event.onset >= 0.0, "Event onset should be non-negative");
            assert!(event.duration >= 0.0, "Event duration should be non-negative");
        }
    }

    Ok(())
}

/// Test dataset with specific features (e.g., multi-echo)
#[test]
fn test_multi_echo_dataset() -> Result<()> {
    let dataset_path = require_example_dataset!("ds000117");

    let project = BidsProject::new(&dataset_path)?;

    // Check for echo entity
    let echo_files = project.search()
        .datatype("func")
        .find_files()?
        .into_iter()
        .filter(|f| f.entities.contains_key("echo"))
        .collect::<Vec<_>>();

    if !echo_files.is_empty() {
        // Verify multiple echoes exist
        let echoes: std::collections::HashSet<_> = echo_files.iter()
            .filter_map(|f| f.entities.get("echo"))
            .collect();

        assert!(echoes.len() > 1, "Multi-echo dataset should have multiple echo times");
    }

    Ok(())
}

/// Test that we can create temporary copies for modification
#[test]
fn test_dataset_temp_copy() -> Result<()> {
    let manager = BidsExamplesManager::new(BidsExamplesManager::default_cache_dir());
    let available = manager.list_available();

    if let Some(example) = available.first() {
        // Create temporary copy
        let temp_copy = create_temp_copy(example)?;
        let temp_path = temp_copy.path().join(&example.name);

        // Verify we can open and modify the temporary copy
        let project = BidsProject::new(&temp_path)?;
        assert_eq!(project.name, example.name);

        // The temporary copy will be automatically cleaned up
    }

    Ok(())
}

/// Test searching across multiple real datasets
#[test]
fn test_cross_dataset_search_patterns() -> Result<()> {
    let manager = BidsExamplesManager::new(BidsExamplesManager::default_cache_dir());
    let available = manager.list_available();

    for example in available.iter().take(5) {
        println!("\nTesting search patterns in: {}", example.name);

        let project = BidsProject::new(&example.path)?;

        // Test various search patterns
        let patterns = vec![
            ("T1w images", project.search().suffix("T1w")),
            ("BOLD data", project.search().suffix("bold")),
            ("JSON sidecars", project.search().extension("json")),
            ("TSV files", project.search().extension("tsv")),
        ];

        for (desc, search) in patterns {
            let files = search.find_files()?;
            if !files.is_empty() {
                println!("  Found {} {}", files.len(), desc);
            }
        }
    }

    Ok(())
}

/// Performance test with larger datasets
#[test]
#[ignore]  // Ignore by default as this might be slow
fn test_performance_large_dataset() -> Result<()> {
    let manager = BidsExamplesManager::new(BidsExamplesManager::default_cache_dir());

    // Find a larger dataset
    let large_examples: Vec<_> = manager.list_available()
        .into_iter()
        .filter(|e| e.size().unwrap_or(0) > 50 * 1024 * 1024)  // > 50MB
        .collect();

    if let Some(example) = large_examples.first() {
        println!("Testing performance with large dataset: {}", example.name);

        let start = std::time::Instant::now();
        let project = BidsProject::new(&example.path)?;
        let load_time = start.elapsed();

        println!("  Project load time: {:?}", load_time);

        // Time various operations
        let start = std::time::Instant::now();
        let all_files = project.search().find_files()?;
        let search_time = start.elapsed();

        println!("  Search all files ({} files): {:?}", all_files.len(), search_time);

        // Performance assertions
        assert!(load_time.as_secs() < 5, "Project loading should be fast");
        assert!(search_time.as_secs() < 2, "File search should be fast");
    }

    Ok(())
}

