//! BIDS Example Datasets Integration
//!
//! This module provides functionality to test against real BIDS example datasets
//! from https://github.com/bids-standard/bids-examples

use std::path::{Path, PathBuf};
use std::fs;
use std::io;

/// List of lightweight BIDS example datasets suitable for testing
/// These are carefully selected to be small enough for CI/CD
pub const EXAMPLE_DATASETS: &[&str] = &[
    "ds000001",  // Single task, multiple runs  
    "ds000002",  // Multiple tasks
    "ds000003",  // Rhyme judgment task
    "ds000117",  // Multi-echo dataset
    "ds000246",  // Mixed design dataset
    "synthetic", // Synthetic dataset
    "ieeg_visual", // iEEG example
    "genetics_ukbb", // Genetics data
];

/// Represents a BIDS example dataset
#[derive(Debug, Clone)]
pub struct BidsExample {
    pub name: String,
    pub path: PathBuf,
    pub description: String,
}

impl BidsExample {
    /// Check if this example dataset exists locally
    pub fn exists(&self) -> bool {
        self.path.exists() && self.path.join("dataset_description.json").exists()
    }

    /// Get the size of the dataset in bytes
    pub fn size(&self) -> io::Result<u64> {
        let mut total_size = 0;
        for entry in walkdir::WalkDir::new(&self.path) {
            let entry = entry?;
            if entry.file_type().is_file() {
                total_size += entry.metadata()?.len();
            }
        }
        Ok(total_size)
    }

    /// Check if dataset is small enough for CI (< 100MB)
    pub fn is_ci_friendly(&self) -> io::Result<bool> {
        Ok(self.size()? < 100 * 1024 * 1024)
    }
}

/// Manager for BIDS example datasets
pub struct BidsExamplesManager {
    cache_dir: PathBuf,
}

impl BidsExamplesManager {
    /// Create a new manager with the specified cache directory
    pub fn new(cache_dir: PathBuf) -> Self {
        Self { cache_dir }
    }

    /// Get the default cache directory
    pub fn default_cache_dir() -> PathBuf {
        let mut path = dirs::cache_dir().unwrap_or_else(|| PathBuf::from("."));
        path.push("bids-rust-test-data");
        path.push("bids-examples");
        path
    }

    /// Get path to a specific example dataset
    pub fn get_dataset_path(&self, name: &str) -> PathBuf {
        self.cache_dir.join(name)
    }

    /// Check if a dataset is available locally
    pub fn is_available(&self, name: &str) -> bool {
        let path = self.get_dataset_path(name);
        path.exists() && path.join("dataset_description.json").exists()
    }

    /// Get all available example datasets
    pub fn list_available(&self) -> Vec<BidsExample> {
        let mut examples = Vec::new();

        if let Ok(entries) = fs::read_dir(&self.cache_dir) {
            for entry in entries.flatten() {
                if entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
                    let path = entry.path();
                    if path.join("dataset_description.json").exists() {
                        if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
                            examples.push(BidsExample {
                                name: name.to_string(),
                                path,
                                description: format!("BIDS example dataset: {}", name),
                            });
                        }
                    }
                }
            }
        }

        examples
    }

    /// Instructions for manually downloading datasets
    pub fn download_instructions(&self, dataset: &str) -> String {
        format!(
            "To use BIDS example dataset '{}', please download it manually:\n\
             1. Visit https://github.com/bids-standard/bids-examples\n\
             2. Download the '{}' directory\n\
             3. Place it in: {}\n\
             4. Ensure dataset_description.json exists in the dataset root",
            dataset,
            dataset,
            self.cache_dir.display()
        )
    }
}

/// Create a temporary copy of an example dataset for testing
/// This allows tests to modify the dataset without affecting the cached version
pub fn create_temp_copy(example: &BidsExample) -> io::Result<tempfile::TempDir> {
    let temp_dir = tempfile::TempDir::new()?;
    let dest = temp_dir.path().join(&example.name);

    // Copy the dataset
    copy_dir_all(&example.path, &dest)?;

    Ok(temp_dir)
}

/// Recursively copy a directory
fn copy_dir_all(src: &Path, dst: &Path) -> io::Result<()> {
    fs::create_dir_all(dst)?;

    for entry in fs::read_dir(src)? {
        let entry = entry?;
        let ty = entry.file_type()?;
        let src_path = entry.path();
        let dst_path = dst.join(entry.file_name());

        if ty.is_dir() {
            copy_dir_all(&src_path, &dst_path)?;
        } else {
            fs::copy(&src_path, &dst_path)?;
        }
    }

    Ok(())
}

/// Helper macro to skip tests if example dataset is not available
#[macro_export]
macro_rules! require_example_dataset {
    ($dataset:expr) => {{
        let manager = $crate::common::bids_examples::BidsExamplesManager::new(
            $crate::common::bids_examples::BidsExamplesManager::default_cache_dir()
        );

        if !manager.is_available($dataset) {
            eprintln!("Skipping test: {}", manager.download_instructions($dataset));
            return Ok(());
        }

        manager.get_dataset_path($dataset)
    }};
}

