//! Mock BIDS dataset creation for testing
//!
//! This module provides utilities for creating temporary BIDS datasets
//! for testing purposes, similar to the R bidser::create_mock_bids function.

use std::fs;
use std::path::{Path, PathBuf};
use tempfile::TempDir;
use serde_json::json;
use std::io::Write;

/// Represents a participant in the BIDS dataset
#[derive(Debug, Clone)]
pub struct Participant {
    pub id: String,
    pub age: Option<u32>,
    pub sex: Option<String>,
    pub handedness: Option<String>,
}

/// Represents a file to be created in the BIDS dataset
#[derive(Debug, Clone)]
pub struct FileSpec {
    pub subject: String,
    pub session: Option<String>,
    pub datatype: String,  // "anat", "func", "dwi", etc.
    pub task: Option<String>,
    pub run: Option<String>,
    pub suffix: String,
    pub extension: String,
    pub space: Option<String>,  // For derivatives
    pub desc: Option<String>,   // For derivatives
    pub is_derivative: bool,
}

/// Event data for functional runs
#[derive(Debug, Clone)]
pub struct EventData {
    pub onset: Vec<f64>,
    pub duration: Vec<f64>,
    pub trial_type: Vec<String>,
}

/// Confound data for functional runs
#[derive(Debug, Clone)]
pub struct ConfoundData {
    pub framewise_displacement: Vec<f64>,
    pub trans_x: Vec<f64>,
    pub trans_y: Vec<f64>,
    pub trans_z: Vec<f64>,
    pub rot_x: Vec<f64>,
    pub rot_y: Vec<f64>,
    pub rot_z: Vec<f64>,
    pub csf: Vec<f64>,
    pub white_matter: Vec<f64>,
}

/// Mock BIDS dataset builder
pub struct MockBidsBuilder {
    project_name: String,
    participants: Vec<Participant>,
    files: Vec<FileSpec>,
    events: Vec<(FileSpec, EventData)>,
    confounds: Vec<(FileSpec, ConfoundData)>,
    dataset_description: Option<serde_json::Value>,
}

impl MockBidsBuilder {
    /// Create a new mock BIDS dataset builder
    pub fn new(project_name: &str) -> Self {
        Self {
            project_name: project_name.to_string(),
            participants: Vec::new(),
            files: Vec::new(),
            events: Vec::new(),
            confounds: Vec::new(),
            dataset_description: None,
        }
    }

    /// Add a participant
    pub fn add_participant(mut self, participant: Participant) -> Self {
        self.participants.push(participant);
        self
    }

    /// Add multiple participants
    pub fn add_participants(mut self, participants: Vec<Participant>) -> Self {
        self.participants.extend(participants);
        self
    }

    /// Add a file specification
    pub fn add_file(mut self, file: FileSpec) -> Self {
        self.files.push(file);
        self
    }

    /// Add multiple file specifications
    pub fn add_files(mut self, files: Vec<FileSpec>) -> Self {
        self.files.extend(files);
        self
    }

    /// Add event data for a functional run
    pub fn add_events(mut self, file_spec: FileSpec, events: EventData) -> Self {
        self.events.push((file_spec, events));
        self
    }

    /// Add confound data for a functional run
    pub fn add_confounds(mut self, file_spec: FileSpec, confounds: ConfoundData) -> Self {
        self.confounds.push((file_spec, confounds));
        self
    }

    /// Set dataset description
    pub fn with_dataset_description(mut self, description: serde_json::Value) -> Self {
        self.dataset_description = Some(description);
        self
    }

    /// Build the mock BIDS dataset in a temporary directory
    pub fn build(self) -> Result<TempDir, Box<dyn std::error::Error>> {
        let temp_dir = TempDir::new()?;
        let root_path = temp_dir.path();

        // Create dataset_description.json
        let project_name = self.project_name.clone();
        let dataset_desc = self.dataset_description.unwrap_or_else(|| {
            json!({
                "Name": project_name,
                "BIDSVersion": "1.9.0",
                "DatasetType": "raw",
                "Authors": ["Test Author"],
                "License": "CC0"
            })
        });

        let desc_path = root_path.join("dataset_description.json");
        fs::write(&desc_path, serde_json::to_string_pretty(&dataset_desc)?)?;

        // Create participants.tsv
        self.create_participants_tsv(root_path)?;

        // Create README
        fs::write(root_path.join("README"), format!("# {}\n\nMock BIDS dataset for testing.", self.project_name))?;

        // Create file structure
        for file_spec in &self.files {
            self.create_file(root_path, file_spec)?;
        }

        // Create event files
        for (file_spec, event_data) in &self.events {
            self.create_event_file(root_path, file_spec, event_data)?;
        }

        // Create confound files
        for (file_spec, confound_data) in &self.confounds {
            self.create_confound_file(root_path, file_spec, confound_data)?;
        }

        Ok(temp_dir)
    }

    /// Create participants.tsv file
    fn create_participants_tsv(&self, root_path: &Path) -> Result<(), Box<dyn std::error::Error>> {
        let mut content = String::from("participant_id\tage\tsex\thandedness\n");

        for participant in &self.participants {
            content.push_str(&format!(
                "{}\t{}\t{}\t{}\n",
                participant.id,
                participant.age.map_or("n/a".to_string(), |a| a.to_string()),
                participant.sex.as_deref().unwrap_or("n/a"),
                participant.handedness.as_deref().unwrap_or("n/a")
            ));
        }

        fs::write(root_path.join("participants.tsv"), content)?;
        Ok(())
    }

    /// Create a file based on FileSpec
    fn create_file(&self, root_path: &Path, file_spec: &FileSpec) -> Result<(), Box<dyn std::error::Error>> {
        let file_path = self.get_file_path(root_path, file_spec);

        // Create directory structure
        if let Some(parent) = file_path.parent() {
            fs::create_dir_all(parent)?;
        }

        // Create file based on type
        match file_spec.extension.as_str() {
            "nii.gz" | "nii" => {
                // Create empty NIfTI file (just placeholder)
                fs::write(&file_path, b"NIFTI_PLACEHOLDER")?;
            }
            "json" => {
                // Create JSON sidecar
                let json_content = self.create_json_sidecar(file_spec);
                fs::write(&file_path, serde_json::to_string_pretty(&json_content)?)?;
            }
            "tsv" => {
                // Create empty TSV file (will be populated by specific functions)
                if !file_path.exists() {
                    fs::write(&file_path, "")?;
                }
            }
            _ => {
                // Create empty file for other types
                fs::write(&file_path, "")?;
            }
        }

        Ok(())
    }

    /// Create event file
    fn create_event_file(&self, root_path: &Path, file_spec: &FileSpec, event_data: &EventData) -> Result<(), Box<dyn std::error::Error>> {
        let file_path = self.get_file_path(root_path, file_spec);

        // Create directory structure
        if let Some(parent) = file_path.parent() {
            fs::create_dir_all(parent)?;
        }

        // Create TSV content
        let mut content = String::from("onset\tduration\ttrial_type\n");
        for i in 0..event_data.onset.len() {
            content.push_str(&format!(
                "{}\t{}\t{}\n",
                event_data.onset[i],
                event_data.duration[i],
                event_data.trial_type[i]
            ));
        }

        fs::write(&file_path, content)?;
        Ok(())
    }

    /// Create confound file
    fn create_confound_file(&self, root_path: &Path, file_spec: &FileSpec, confound_data: &ConfoundData) -> Result<(), Box<dyn std::error::Error>> {
        let file_path = self.get_file_path(root_path, file_spec);

        // Create directory structure
        if let Some(parent) = file_path.parent() {
            fs::create_dir_all(parent)?;
        }

        // Create TSV content
        let mut content = String::from("framewise_displacement\ttrans_x\ttrans_y\ttrans_z\trot_x\trot_y\trot_z\tcsf\twhite_matter\n");

        let n_timepoints = confound_data.framewise_displacement.len();
        for i in 0..n_timepoints {
            content.push_str(&format!(
                "{}\t{}\t{}\t{}\t{}\t{}\t{}\t{}\t{}\n",
                confound_data.framewise_displacement[i],
                confound_data.trans_x[i],
                confound_data.trans_y[i],
                confound_data.trans_z[i],
                confound_data.rot_x[i],
                confound_data.rot_y[i],
                confound_data.rot_z[i],
                confound_data.csf[i],
                confound_data.white_matter[i]
            ));
        }

        fs::write(&file_path, content)?;
        Ok(())
    }

    /// Get the full file path for a FileSpec
    fn get_file_path(&self, root_path: &Path, file_spec: &FileSpec) -> PathBuf {
        let mut path = PathBuf::from(root_path);

        // Add derivatives path if needed
        if file_spec.is_derivative {
            path.push("derivatives");
            path.push("fmriprep");
        }

        // Add subject directory
        let sub_dir = if file_spec.subject.starts_with("sub-") {
            file_spec.subject.clone()
        } else {
            format!("sub-{}", file_spec.subject)
        };
        path.push(&sub_dir);

        // Add session directory if present
        if let Some(ses) = &file_spec.session {
            let ses_dir = if ses.starts_with("ses-") {
                ses.clone()
            } else {
                format!("ses-{}", ses)
            };
            path.push(&ses_dir);
        }

        // Add datatype directory
        path.push(&file_spec.datatype);

        // Build filename
        let filename = self.build_filename(file_spec);
        path.push(filename);

        path
    }

    /// Build BIDS filename from FileSpec
    fn build_filename(&self, file_spec: &FileSpec) -> String {
        let mut parts = Vec::new();

        // Subject
        if file_spec.subject.starts_with("sub-") {
            parts.push(file_spec.subject.clone());
        } else {
            parts.push(format!("sub-{}", file_spec.subject));
        }

        // Session
        if let Some(ses) = &file_spec.session {
            if ses.starts_with("ses-") {
                parts.push(ses.clone());
            } else {
                parts.push(format!("ses-{}", ses));
            }
        }

        // Task
        if let Some(task) = &file_spec.task {
            parts.push(format!("task-{}", task));
        }

        // Run
        if let Some(run) = &file_spec.run {
            parts.push(format!("run-{}", run));
        }

        // Space (derivatives)
        if let Some(space) = &file_spec.space {
            parts.push(format!("space-{}", space));
        }

        // Description (derivatives)
        if let Some(desc) = &file_spec.desc {
            parts.push(format!("desc-{}", desc));
        }

        // Join parts with underscores and add suffix/extension
        let base = parts.join("_");
        format!("{}_{}.{}", base, file_spec.suffix, file_spec.extension)
    }

    /// Create JSON sidecar content
    fn create_json_sidecar(&self, file_spec: &FileSpec) -> serde_json::Value {
        match file_spec.suffix.as_str() {
            "bold" => json!({
                "TaskName": file_spec.task.as_deref().unwrap_or("rest"),
                "RepetitionTime": 2.0,
                "EchoTime": 0.03,
                "FlipAngle": 90,
                "SliceTiming": [0.0, 0.5, 1.0, 1.5]
            }),
            "T1w" | "T2w" => json!({
                "MagneticFieldStrength": 3.0,
                "Manufacturer": "MockScanner",
                "SequenceName": "MPRAGE"
            }),
            _ => json!({})
        }
    }
}

