/// Build the mock BIDS dataset in a temporary directory
pub fn build(self) -> Result<TempDir, Box<dyn std::error::Error>> {
    let temp_dir = TempDir::new()?;
    let root_path = temp_dir.path();

    // Extract values we need before consuming self
    let project_name = self.project_name.clone();
    let dataset_desc = self.dataset_description.unwrap_or_else(|| {
        json!({
            "Name": project_name,
            "BIDSVersion": "1.9.0",
            "DatasetType": "raw",
            "Authors": ["Test Author"],
            "License": "CC0"
        })
