/// Create a mock BIDS dataset with derivatives
pub fn create_bids_with_derivatives() -> Result<TempDir, Box<dyn std::error::Error>> {
    let base_files = vec![
        // Raw data
        FileSpec {
            subject: "01".to_string(),
            session: None,
            datatype: "anat".to_string(),
            task: None,
            run: None,
            suffix: "T1w".to_string(),
            extension: "nii.gz".to_string(),
            space: None,
            desc: None,
            is_derivative: false,
        },
        FileSpec {
            subject: "01".to_string(),
            session: None,
            datatype: "func".to_string(),
            task: Some("rest".to_string()),
            run: Some("01".to_string()),
            suffix: "bold".to_string(),
            extension: "nii.gz".to_string(),
            space: None,
            desc: None,
            is_derivative: false,
        },
    ];

    let derivative_files = vec![
        // Preprocessed anatomical
        FileSpec {
            subject: "01".to_string(),
            session: None,
            datatype: "anat".to_string(),
            task: None,
            run: None,
            suffix: "T1w".to_string(),
            extension: "nii.gz".to_string(),
            space: Some("MNI152NLin2009cAsym".to_string()),
            desc: Some("preproc".to_string()),
            is_derivative: true,
        },
        // Preprocessed functional
        FileSpec {
            subject: "01".to_string(),
            session: None,
            datatype: "func".to_string(),
            task: Some("rest".to_string()),
            run: Some("01".to_string()),
            suffix: "bold".to_string(),
            extension: "nii.gz".to_string(),
            space: Some("MNI152NLin2009cAsym".to_string()),
            desc: Some("preproc".to_string()),
            is_derivative: true,
        },
        // Confounds
        FileSpec {
            subject: "01".to_string(),
            session: None,
            datatype: "func".to_string(),
            task: Some("rest".to_string()),
            run: Some("01".to_string()),
            suffix: "timeseries".to_string(),
            extension: "tsv".to_string(),
            space: None,
            desc: Some("confounds".to_string()),
            is_derivative: true,
        },
    ];

    let mut builder = MockBidsBuilder::new("test_derivatives")
        .add_participant(Participant {
            id: "sub-01".to_string(),
            age: Some(25),
            sex: Some("M".to_string()),
            handedness: Some("R".to_string()),
        })
        .add_files(base_files)
        .add_files(derivative_files);

    // Add confound data
    let confound_spec = FileSpec {
        subject: "01".to_string(),
        session: None,
        datatype: "func".to_string(),
        task: Some("rest".to_string()),
        run: Some("01".to_string()),
        suffix: "timeseries".to_string(),
        extension: "tsv".to_string(),
        space: None,
        desc: Some("confounds".to_string()),
        is_derivative: true,
    };

    let n_timepoints = 100;
    let confound_data = ConfoundData {
        framewise_displacement: (0..n_timepoints).map(|i| 0.1 + 0.01 * (i as f64)).collect(),
        trans_x: (0..n_timepoints).map(|i| 0.01 * (i as f64).sin()).collect(),
        trans_y: (0..n_timepoints).map(|i| 0.01 * (i as f64).cos()).collect(),
        trans_z: (0..n_timepoints).map(|i| 0.005 * (i as f64).sin()).collect(),
        rot_x: (0..n_timepoints).map(|i| 0.001 * (i as f64).cos()).collect(),
        rot_y: (0..n_timepoints).map(|i| 0.001 * (i as f64).sin()).collect(),
        rot_z: (0..n_timepoints).map(|i| 0.0005 * (i as f64).cos()).collect(),
        csf: (0..n_timepoints).map(|i| 100.0 + 5.0 * (i as f64 * 0.1).sin()).collect(),
        white_matter: (0..n_timepoints).map(|i| 150.0 + 3.0 * (i as f64 * 0.1).cos()).collect(),
    };

    builder = builder.add_confounds(confound_spec, confound_data);

    builder.build()
}

